mapper.select:
SELECT alert_id AS alertId, alert_level AS alertLevel, alert_type AS alertType, alert_title AS alertTitle, alert_content AS alertContent, status, trigger_time AS triggerTime, resolve_time AS resolveTime, resolved_by AS resolvedBy, resolved_by_name AS resolvedByName, resolve_remark AS resolveRemark, create_time AS createTime FROM sys_monitor_alert
AND alert_level = #{req.alertLevel}
AND status = #{req.status}
AND DATE(trigger_time) >= #{req.startDate}
AND DATE(trigger_time) <= #{req.endDate}
ORDER BY trigger_time DESC
